        for row in range(3):
            for col in range((row % 2) + 1, 8, 2):
                self.board[row][col] = -1
        for row in range(5, 8):
            for col in range((row % 2) + 1, 8, 2):
                self.board[row][col] = 1

    def display_board(self):
        # Display the board in a readable format
        print(np.flipud(np.where(self.board == -1, 'B', np.where(self.board == 1, 'W', ' '))))
